CREATE TABLE email_templates (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, category text NOT NULL, created_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE email_template_versions (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), template_id uuid NOT NULL REFERENCES email_templates(id) ON DELETE CASCADE, version integer NOT NULL, subject text NOT NULL, body text NOT NULL, created_at timestamptz NOT NULL DEFAULT now(), UNIQUE(template_id, version)); CREATE TABLE campaigns (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, objective text, template_id uuid REFERENCES email_templates(id) ON DELETE SET NULL, created_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE campaign_members (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), campaign_id uuid NOT NULL REFERENCES campaigns(id) ON DELETE CASCADE, director_id uuid REFERENCES directors(id) ON DELETE SET NULL, school_id uuid REFERENCES schools(id) ON DELETE SET NULL, status text NOT NULL DEFAULT 'not_started', created_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE campaign_member_status_history (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), member_id uuid NOT NULL REFERENCES campaign_members(id) ON DELETE CASCADE, status text NOT NULL, created_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE draft_requests (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), campaign_member_id uuid REFERENCES campaign_members(id) ON DELETE SET NULL, template_version_id uuid REFERENCES email_template_versions(id) ON DELETE SET NULL, recipient text NOT NULL, subject text NOT NULL, body text NOT NULL, status text NOT NULL DEFAULT 'pending_review', created_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE outlook_draft_refs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), draft_request_id uuid NOT NULL REFERENCES draft_requests(id) ON DELETE CASCADE, external_message_id text, compose_url text, created_at timestamptz NOT NULL DEFAULT now());
